    47→      return;
    48→    }
    49→    console.log("Retrying MongoDB connection...");
    50→    const ok = await tryConnect(uri);
    51→    if (ok && retryInterval) { clearInterval(retryInterval); retryInterval = null; }
    52→  }, 30000);
