@import url('https://fonts.googleapis.com/css2?family=Alexandria:wght@100;200;300;400;500;600;700;800;900&family=Noto+Serif+JP:wght@400;500;600;700;900&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* ── Mobile hardening: prevent any horizontal overflow ────────── */
html, body { max-width: 100vw; overflow-x: hidden; }
img, video, iframe { max-width: 100%; height: auto; }
@media (max-width: 640px) {
  .container { padding-left: 0.875rem !important; padding-right: 0.875rem !important; }
  button, a { -webkit-tap-highlight-color: transparent; }
}

/* ── FUJI CAFE PALETTE — لوحة ألوان فوجي كافيه ────────────────────
   #E8637A  Fuji Pink        (primary brand pink from logo)
   #1A1A1A  Fuji Black       (deep black)
   #6B3F2A  Coffee Brown     (rich espresso)
   #FAF6F0  Cream White      (warm background)
   #C8956C  Caramel          (accent warm tone)
   ─────────────────────────────────────────────────────────────────── */

:root {
  --background: 36 30% 97%;
  --foreground: 0 0% 10%;

  --card: 0 0% 100%;
  --card-foreground: 0 0% 10%;

  --popover: 0 0% 100%;
  --popover-foreground: 0 0% 10%;

  /* Primary = Fuji Pink #E8637A */
  --primary: 350 74% 65%;
  --primary-foreground: 0 0% 100%;

  --secondary: 36 30% 95%;
  --secondary-foreground: 20 40% 25%;

  --muted: 36 20% 94%;
  --muted-foreground: 0 0% 45%;

  --accent: 36 30% 93%;
  --accent-foreground: 20 40% 25%;

  /* Destructive = Coffee Brown */
  --destructive: 16 43% 29%;
  --destructive-foreground: 0 0% 100%;

  --border: 36 20% 88%;
  --input: 36 20% 88%;
  --ring: 350 74% 65%;

  --radius: 0.75rem;

  /* Brand tokens */
  --brand-pink: #E8637A;
  --brand-pink-dark: #d44f66;
  --brand-pink-light: #f08a9d;
  --brand-brown: #6B3F2A;
  --brand-brown-dark: #4f2e1e;
  --brand-brown-light: #8B5A3C;
  --brand-caramel: #C8956C;
  --brand-black: #1A1A1A;
  --brand-cream: #FAF6F0;

  /* Backwards-compat */
  --gold: #E8637A;
  --gold-light: #f08a9d;
  --gold-dark: #d44f66;
}

@layer utilities {
  .hover-elevate {
    @apply transition-all duration-300 hover:-translate-y-1 hover:shadow-xl;
  }
  .luxury-glass {
    @apply bg-white/80 backdrop-blur-md border border-white/40 shadow-xl;
  }
  .text-gradient-pink {
    background: linear-gradient(135deg, #E8637A, #f08a9d, #E8637A);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .text-gradient-coffee {
    background: linear-gradient(135deg, #E8637A 0%, #6B3F2A 50%, #C8956C 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .text-gradient-gold {
    background: linear-gradient(135deg, #E8637A, #f08a9d, #E8637A);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .text-gradient-sovereign {
    background: linear-gradient(135deg, #E8637A 0%, #6B3F2A 50%, #C8956C 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .bg-gold {
    background: linear-gradient(135deg, #E8637A, #d44f66);
  }
  .bg-sovereign {
    background: linear-gradient(135deg, #6B3F2A 0%, #4f2e1e 100%);
  }
  .bg-crimson {
    background: linear-gradient(135deg, #E8637A 0%, #d44f66 100%);
  }
  .border-gold {
    border-color: #E8637A;
  }
  .font-display {
    font-family: 'Noto Serif JP', 'Alexandria', serif;
  }
  .font-japanese {
    font-family: 'Noto Serif JP', serif;
  }
}

.dark {
  --background: 20 15% 8%;
  --foreground: 36 20% 92%;

  --card: 20 12% 11%;
  --card-foreground: 36 20% 92%;

  --popover: 20 12% 11%;
  --popover-foreground: 36 20% 92%;

  /* Primary = Fuji Pink (slightly lighter in dark) */
  --primary: 350 70% 68%;
  --primary-foreground: 0 0% 100%;

  --secondary: 20 12% 15%;
  --secondary-foreground: 36 20% 85%;

  --muted: 20 10% 18%;
  --muted-foreground: 36 10% 60%;

  --accent: 20 12% 16%;
  --accent-foreground: 36 20% 85%;

  --destructive: 16 43% 40%;
  --destructive-foreground: 0 0% 100%;

  --border: 20 12% 20%;
  --input: 20 12% 20%;
  --ring: 350 70% 68%;
}

body {
  font-family: 'Alexandria', 'Noto Serif JP', sans-serif;
  background-color: hsl(var(--background));
  color: hsl(var(--foreground));
}

/* Scrollbar styling */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: hsl(var(--muted)); }
::-webkit-scrollbar-thumb { background: var(--brand-pink); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--brand-pink-dark); }

/* Smooth scroll */
html { scroll-behavior: smooth; }

/* Selection color */
::selection { background: #E8637A33; color: #1A1A1A; }

/* Custom animations */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes shimmer {
  0% { background-position: -200% center; }
  100% { background-position: 200% center; }
}
@keyframes pulse-pink {
  0%, 100% { box-shadow: 0 0 0 0 rgba(232, 99, 122, 0.4); }
  50% { box-shadow: 0 0 0 8px rgba(232, 99, 122, 0); }
}

.animate-fade-in-up { animation: fadeInUp 0.6s ease forwards; }
.animate-shimmer {
  background: linear-gradient(90deg, transparent 0%, rgba(232,99,122,0.15) 50%, transparent 100%);
  background-size: 200% 100%;
  animation: shimmer 2s infinite;
}
.animate-pulse-pink { animation: pulse-pink 2s infinite; }

/* Focus visible for accessibility */
:focus-visible { outline: 2px solid var(--brand-pink); outline-offset: 2px; }

/* RTL fixes */
[dir="rtl"] .ltr-only { direction: ltr; }

